import subprocess
import json
import logging
import shlex
import os
import pika

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define an explicit allowlist of permitted commands
ALLOWED_COMMANDS = {
    "data_export": {
        "executable": "/usr/local/bin/data_export.sh",
        "allowed_args_pattern": None,  # no extra args allowed
    },
    "generate_report": {
        "executable": "/usr/local/bin/generate_report.py",
        "allowed_args_pattern": None,
    },
    "compress_logs": {
        "executable": "/usr/local/bin/compress_logs.sh",
        "allowed_args_pattern": None,
    },
}

# Characters/patterns that should never appear in arguments
DANGEROUS_PATTERNS = [";", "&&", "||", "|", "`", "$(", "${", ">", "<", "\n", "\r"]


def validate_argument(arg: str) -> bool:
    """Validate that an argument doesn't contain shell injection patterns."""
    for pattern in DANGEROUS_PATTERNS:
        if pattern in arg:
            logger.warning(f"Dangerous pattern '{pattern}' found in argument: {arg}")
            return False
    # Reject absolute paths or path traversal
    if ".." in arg:
        logger.warning(f"Path traversal detected in argument: {arg}")
        return False
    return True


def build_safe_command(job_name: str, args: list) -> list:
    """Build a safe command list from the allowlisted job name and validated args."""
    if job_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Command '{job_name}' is not in the allowlist")

    config = ALLOWED_COMMANDS[job_name]
    executable = config["executable"]

    if not os.path.isfile(executable):
        raise FileNotFoundError(f"Executable not found: {executable}")

    # Validate each argument
    safe_args = []
    for arg in (args or []):
        arg_str = str(arg)
        if not validate_argument(arg_str):
            raise ValueError(f"Invalid argument rejected: {arg_str}")
        safe_args.append(arg_str)

    return [executable] + safe_args


def process_message(ch, method, properties, body):
    """Process a job message from the queue."""
    try:
        message = json.loads(body.decode("utf-8"))
        job_name = message.get("job_name")
        job_args = message.get("args", [])
        job_id = message.get("job_id", "unknown")

        logger.info(f"Received job: {job_id} - {job_name}")

        # Build a validated, safe command — NO shell=True, NO arbitrary commands
        command = build_safe_command(job_name, job_args)

        logger.info(f"Executing job {job_id}: {command}")

        result = subprocess.run(
            command,
            shell=False,  # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=300,  # 5 minute timeout
            cwd="/tmp/job_workdir",  # restricted working directory
            env={  # minimal environment
                "PATH": "/usr/local/bin:/usr/bin",
                "HOME": "/tmp",
                "JOB_ID": str(job_id),
            },
        )

        if result.returncode == 0:
            logger.info(f"Job {job_id} completed successfully. stdout: {result.stdout[:500]}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        else:
            logger.error(
                f"Job {job_id} failed with return code {result.returncode}. "
                f"stderr: {result.stderr[:500]}"
            )
            # Reject and don't requeue on failure (send to dead letter queue)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    except (json.JSONDecodeError, ValueError, FileNotFoundError) as e:
        logger.error(f"Invalid message rejected: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except subprocess.TimeoutExpired:
        logger.error(f"Job {job_id} timed out")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        logger.exception(f"Unexpected error processing message: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)


def main():
    """Main consumer loop."""
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", 5672))
    rabbitmq_user = os.environ.get("RABBITMQ_USER", "guest")
    rabbitmq_pass = os.environ.get("RABBITMQ_PASS", "guest")
    queue_name = os.environ.get("JOB_QUEUE", "jobs")

    credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_pass)
    connection_params = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        credentials=credentials,
        heartbeat=600,
    )

    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()

    # Declare queue with dead letter exchange for failed messages
    channel.queue_declare(
        queue=queue_name,
        durable=True,
        arguments={
            "x-dead-letter-exchange": "dlx",
            "x-dead-letter-routing-key": "failed_jobs",
        },
    )

    # Process one message at a time
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=queue_name, on_message_callback=process_message)

    logger.info(f"Consumer started. Waiting for jobs on queue '{queue_name}'...")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down consumer...")
        channel.stop_consuming()
    finally:
        connection.close()


if __name__ == "__main__":
    os.makedirs("/tmp/job_workdir", exist_ok=True)
    main()